    41→    /**
    42→     * Wait for all jobs to complete
    43→     * @param jobs The jobs
    44→     * @param callback This will be called to handle the exception caused by each Future#get
    45→     * @return true if all pass. Otherwise, false
    46→     */
    47→    public static boolean waitForAllToComplete(List<Future<?>> jobs, Consumer<Throwable> callback) {
    48→        List<Future<?>> failed = new ArrayList<>();
    49→        for (Future<?> job : jobs) {
    50→            try {
    51→                job.get();
    52→            } catch (Exception e) {
    53→                callback.accept(e);
    54→                failed.add(job);
    55→            }
    56→        }
    57→        return failed.isEmpty();
    58→    }
    59→
    60→    /**
    61→     * Returns true if the given log should not be on the current broker
    62→     * according to the metadata image.
    63→     *
    64→     * @param brokerId       The ID of the current broker.
    65→     * @param newTopicsImage The new topics image after broker has been reloaded
    66→     * @param log            The log object to check
    67→     * @return true if the log should not exist on the broker, false otherwise.
    68→     */
    69→    public static boolean isStrayKraftReplica(int brokerId, TopicsImage newTopicsImage, UnifiedLog log) {
    70→        if (log.topicId().isEmpty()) {
    71→            // Missing topic ID could result from storage failure or unclean shutdown after topic creation but before flushing
    72→            // data to the `partition.metadata` file. And before appending data to the log, the `partition.metadata` is always
    73→            // flushed to disk. So if the topic ID is missing, it mostly means no data was appended, and we can treat this as
    74→            // a stray log.
    75→            LOG.info("The topicId does not exist in {}, treat it as a stray log.", log);
    76→            return true;
    77→        }
    78→
    79→        Uuid topicId = log.topicId().get();
    80→        int partitionId = log.topicPartition().partition();
    81→        PartitionRegistration partition = newTopicsImage.getPartition(topicId, partitionId);
    82→        if (partition == null) {
    83→            LOG.info("Found stray log dir {}: the topicId {} does not exist in the metadata image.", log, topicId);
    84→            return true;
    85→        } else {
    86→            List<Integer> replicas = Arrays.stream(partition.replicas).boxed().toList();
    87→            if (!replicas.contains(brokerId)) {
    88→                LOG.info("Found stray log dir {}: the current replica assignment {} does not contain the local brokerId {}.",
    89→                        log, replicas.stream().map(String::valueOf).collect(Collectors.joining(", ", "[", "]")), brokerId);
    90→                return true;
    91→            } else {
    92→                return false;
    93→            }
    94→        }
    95→    }
    96→}
